+// ---------------------------------------------------------------------------
+// Footer Parsing
+// ---------------------------------------------------------------------------
+
+interface RecordBatchBlock {
+  offset: number;  // byte offset from start of file
+  metaDataLength: number;
+  bodyLength: number;
+}
