+      }
+      return arr.buffer;
+    }
+    case "float32": {
+      const arr = new Float32Array(values.length);
+      for (let i = 0; i < values.length; i++) arr[i] = Number(values[i] ?? 0);
+      return arr.buffer;
+    }
+    case "float64": {
