+    // Find first non-whitespace byte
+    let first = 0;
+    for (let i = 0; i < head.length; i++) {
+      const b = head[i];
+      if (b === 0x20 || b === 0x09 || b === 0x0a || b === 0x0d) continue;
+      // Skip BOM (0xEF 0xBB 0xBF)
+      if (b === 0xef && i + 2 < head.length && head[i + 1] === 0xbb && head[i + 2] === 0xbf) {
+        i += 2;
+        continue;
+      }
+      first = b;
+      break;
+    }
